import pandas as pd

from pytexera import *
class Operator(UDFGeneralOperator):
    def process_table_0(self, df1: pd.DataFrame, df2: pd.DataFrame):
        self.filtered: pd.Series = df1[df1['x'] > 0]
        self.merged = pd.merge(self.filtered, df2, on='id', how='inner')
        yield None
    def process_table_1(self):
        self.merged['score'] = self.merged['x'] * self.merged['w']
        self.projected = self.merged[['id', 'score']]
        yield {'projected': self.projected}
        yield None
